              <div style={{fontSize:36,fontWeight:800,color:"#3B82F6",letterSpacing:-1.5}}>{PENDING_SKUS.length}<span style={{fontSize:14,fontWeight:500,color:"#93C5FD",marginLeft:4}}>건</span></div>
